import React, { useState, useCallback } from 'react';

// 8 pairs — manageable for Grade 3, no time pressure
const CARD_DATA = [
  { id: 'tree',      emoji: '🌳', label: 'Tree',      isLiving: true  },
  { id: 'stone',     emoji: '🪨', label: 'Stone',     isLiving: false },
  { id: 'fish',      emoji: '🐟', label: 'Fish',      isLiving: true  },
  { id: 'car',       emoji: '🚗', label: 'Car',       isLiving: false },
  { id: 'butterfly', emoji: '🦋', label: 'Butterfly', isLiving: true  },
  { id: 'chair',     emoji: '🪑', label: 'Chair',     isLiving: false },
  { id: 'worm',      emoji: '🪱', label: 'Earthworm', isLiving: true  },
  { id: 'book',      emoji: '📚', label: 'Book',      isLiving: false },
];

function shuffle(arr) {
  return [...arr].sort(() => Math.random() - 0.5);
}

function buildDeck() {
  // Each card has a pair: one with category label, one with item
  // We create pairs: (emoji card) matches (category card: Living/Non-Living)
  return shuffle(
    CARD_DATA.flatMap((c, i) => [
      { uid: `item-${i}`, type: 'item',     pairId: c.id, emoji: c.emoji, label: c.label,   isLiving: c.isLiving },
      { uid: `cat-${i}`,  type: 'category', pairId: c.id, emoji: c.isLiving ? '🌿' : '🪨',
        label: c.isLiving ? 'Living Thing' : 'Non-Living', isLiving: c.isLiving },
    ])
  );
}

export default function MemoryGame() {
  const [deck, setDeck]       = useState(() => buildDeck());
  const [flipped, setFlipped] = useState([]);
  const [matched, setMatched] = useState(new Set());
  const [wrong, setWrong]     = useState([]);
  const [moves, setMoves]     = useState(0);
  const [done, setDone]       = useState(false);

  const handleFlip = useCallback((idx) => {
    if (flipped.length === 2) return;
    if (flipped.includes(idx)) return;
    if (matched.has(deck[idx].pairId)) return;
    if (wrong.includes(idx)) return;

    const next = [...flipped, idx];
    setFlipped(next);

    if (next.length === 2) {
      setMoves(m => m + 1);
      const [a, b] = next;
      const cardA = deck[a], cardB = deck[b];
      const isMatch = cardA.pairId === cardB.pairId && cardA.type !== cardB.type;

      if (isMatch) {
        const newMatched = new Set([...matched, cardA.pairId]);
        setMatched(newMatched);
        setFlipped([]);
        if (newMatched.size === CARD_DATA.length) setTimeout(() => setDone(true), 500);
      } else {
        setWrong(next);
        setTimeout(() => { setFlipped([]); setWrong([]); }, 1000);
      }
    }
  }, [flipped, matched, wrong, deck]);

  const reset = () => {
    setDeck(buildDeck());
    setFlipped([]); setMatched(new Set()); setWrong([]);
    setMoves(0); setDone(false);
  };

  return (
    <div style={{ fontFamily: 'var(--font-body)' }}>
      {/* Header */}
      <div style={{
        background: 'linear-gradient(135deg, #0f766e, #0d9488)',
        borderRadius: '20px', padding: '20px 24px', marginBottom: '20px',
        color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'space-between'
      }}>
        <div>
          <div style={{ fontFamily: 'var(--font-display)', fontSize: '20px' }}>🧠 Memory Match</div>
          <div style={{ opacity: 0.85, fontSize: '13px', fontWeight: 600, marginTop: '2px' }}>
            Match each animal or object to its category — Living 🌿 or Non-Living 🪨. Take your time!
          </div>
        </div>
        <div style={{ display: 'flex', gap: '16px', alignItems: 'center' }}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontFamily: 'var(--font-display)', fontSize: '22px' }}>{moves}</div>
            <div style={{ fontSize: '11px', opacity: 0.8, fontWeight: 700 }}>MOVES</div>
          </div>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontFamily: 'var(--font-display)', fontSize: '22px' }}>{matched.size}/{CARD_DATA.length}</div>
            <div style={{ fontSize: '11px', opacity: 0.8, fontWeight: 700 }}>MATCHED</div>
          </div>
        </div>
      </div>

      {/* Progress */}
      <div style={{ background: '#e5e7eb', borderRadius: '50px', height: '10px', marginBottom: '20px', overflow: 'hidden' }}>
        <div style={{
          height: '100%', borderRadius: '50px',
          background: 'linear-gradient(90deg, #0d9488, #4ade80)',
          width: `${(matched.size / CARD_DATA.length) * 100}%`,
          transition: 'width 0.5s ease'
        }}/>
      </div>

      {/* Grid */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '12px', marginBottom: '16px' }}>
        {deck.map((card, idx) => {
          const isFlipped = flipped.includes(idx) || matched.has(card.pairId);
          const isWrong   = wrong.includes(idx);
          const isMatched = matched.has(card.pairId);

          return (
            <div key={card.uid} onClick={() => handleFlip(idx)} style={{
              height: '88px', borderRadius: '14px', cursor: isMatched ? 'default' : 'pointer',
              perspective: '600px', userSelect: 'none',
              transform: isMatched ? 'scale(0.96)' : 'scale(1)',
              transition: 'transform 0.2s'
            }}>
              <div style={{
                width: '100%', height: '100%', position: 'relative',
                transformStyle: 'preserve-3d',
                transform: isFlipped ? 'rotateY(180deg)' : 'rotateY(0deg)',
                transition: 'transform 0.4s cubic-bezier(0.4,0,0.2,1)'
              }}>
                {/* Back */}
                <div style={{
                  position: 'absolute', inset: 0, backfaceVisibility: 'hidden',
                  background: 'linear-gradient(135deg, #134e4a, #0f766e)',
                  borderRadius: '14px', display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: '24px', border: '2px solid rgba(255,255,255,0.1)',
                  boxShadow: '0 3px 8px rgba(0,0,0,0.15)'
                }}>🌿</div>
                {/* Front */}
                <div style={{
                  position: 'absolute', inset: 0, backfaceVisibility: 'hidden',
                  transform: 'rotateY(180deg)',
                  background: isMatched
                    ? (card.isLiving ? '#dcfce7' : '#f1f5f9')
                    : isWrong ? '#fee2e2' : 'white',
                  borderRadius: '14px',
                  border: `2.5px solid ${isMatched ? (card.isLiving ? '#4ade80' : '#94a3b8') : isWrong ? '#fca5a5' : '#e5e7eb'}`,
                  display: 'flex', flexDirection: 'column',
                  alignItems: 'center', justifyContent: 'center', gap: '4px',
                  padding: '6px',
                  boxShadow: isMatched ? `0 0 0 3px ${card.isLiving ? '#4ade8050' : '#94a3b850'}` : 'none'
                }}>
                  <div style={{ fontSize: '26px', lineHeight: 1 }}>{card.emoji}</div>
                  <div style={{
                    fontSize: '10px', fontWeight: 900, textAlign: 'center', lineHeight: 1.2,
                    color: isMatched ? (card.isLiving ? '#166534' : '#475569') : '#374151'
                  }}>{card.label}</div>
                  {isMatched && <div style={{ fontSize: '12px' }}>✅</div>}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <div style={{ display: 'flex', gap: '12px', alignItems: 'center', justifyContent: 'space-between' }}>
        <div style={{ fontSize: '13px', fontWeight: 700, color: '#6b7280' }}>
          💡 Tip: Match each item (🌳🐟🚗) to its category card (🌿 Living / 🪨 Non-Living)
        </div>
        <button onClick={reset} style={{
          background: '#f1f5f9', border: '2px solid #e2e8f0', borderRadius: '50px',
          padding: '8px 20px', fontFamily: 'var(--font-body)', fontWeight: 800,
          fontSize: '13px', cursor: 'pointer', color: '#475569'
        }}>🔄 New Game</button>
      </div>

      {done && (
        <div style={{
          position: 'absolute', inset: 0, background: 'rgba(0,0,0,0.55)',
          borderRadius: '20px', display: 'flex', alignItems: 'center', justifyContent: 'center',
          zIndex: 10, animation: 'fadeIn 0.3s ease'
        }}>
          <div style={{
            background: 'white', borderRadius: '24px', padding: '40px 36px',
            textAlign: 'center', maxWidth: '340px', animation: 'popIn 0.4s ease'
          }}>
            <div style={{ fontSize: '60px', marginBottom: '12px' }}>🏆</div>
            <div style={{ fontFamily: 'var(--font-display)', fontSize: '26px', color: '#0f766e', marginBottom: '8px' }}>
              You found all pairs!
            </div>
            <div style={{ color: '#6b7280', fontWeight: 600, marginBottom: '8px' }}>
              Completed in {moves} moves
            </div>
            <div style={{ fontSize: '36px', margin: '12px 0' }}>⭐⭐⭐</div>
            <div style={{ fontWeight: 700, color: '#374151', marginBottom: '20px', fontSize: '14px' }}>
              🌟 Amazing work! You know the difference between Living and Non-Living things!
            </div>
            <button onClick={reset} style={{
              background: 'linear-gradient(135deg, #0f766e, #0d9488)', color: 'white',
              border: 'none', borderRadius: '50px', padding: '12px 28px',
              fontFamily: 'var(--font-body)', fontWeight: 800, fontSize: '15px', cursor: 'pointer'
            }}>🔄 Play Again</button>
          </div>
        </div>
      )}
    </div>
  );
}
